// Smooth scrolling for navigation
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function (e) {
        e.preventDefault();
        const target = document.querySelector(this.getAttribute('href'));
        if (target) {
            target.scrollIntoView({
                behavior: 'smooth',
                block: 'start'
            });
        }
    });
});

// Intersection Observer for fade-in animations
const observerOptions = {
    root: null,
    rootMargin: '0px',
    threshold: 0.1
};

const observer = new IntersectionObserver((entries, observer) => {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            entry.target.classList.add('visible');
            observer.unobserve(entry.target);
        }
    });
}, observerOptions);

document.addEventListener('DOMContentLoaded', () => {
    const sections = document.querySelectorAll('section');
    sections.forEach(section => {
        section.classList.add('fade-in');
        observer.observe(section);
    });
});

// --- PDF.JS RENDERER ---
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

function renderPDF(pdfData) {
    var raw = window.atob(pdfData);
    var rawLength = raw.length;
    var array = new Uint8Array(new ArrayBuffer(rawLength));
    for(var i = 0; i < rawLength; i++) {
        array[i] = raw.charCodeAt(i);
    }
    
    const loadingTask = pdfjsLib.getDocument({data: array});
    loadingTask.promise.then(function(pdf) {
        pdf.getPage(1).then(function(page) {
            var scale = 2; // high resolution render
            var viewport = page.getViewport({scale: scale});

            var canvas = document.getElementById('resume-canvas');
            var context = canvas.getContext('2d');
            canvas.height = viewport.height;
            canvas.width = viewport.width;

            var renderContext = {
                canvasContext: context,
                viewport: viewport
            };
            page.render(renderContext);
        });
    }).catch(function (reason) {
        console.error('Error rendering PDF: ', reason);
    });
}

// --- GALLERY PDF RENDERER ---
function renderGalleryPDF(pdfData, canvasId) {
    var raw = window.atob(pdfData);
    var rawLength = raw.length;
    var array = new Uint8Array(new ArrayBuffer(rawLength));
    for(var i = 0; i < rawLength; i++) {
        array[i] = raw.charCodeAt(i);
    }

    const loadingTask = pdfjsLib.getDocument({data: array});
    loadingTask.promise.then(function(pdf) {
        pdf.getPage(1).then(function(page) {
            var scale = 2; // high resolution render
            var viewport = page.getViewport({scale: scale});

            var canvas = document.getElementById(canvasId);
            if (!canvas) return;
            var context = canvas.getContext('2d');
            canvas.height = viewport.height;
            canvas.width = viewport.width;

            var renderContext = {
                canvasContext: context,
                viewport: viewport
            };
            page.render(renderContext);
        });
    }).catch(function (reason) {
        console.error('Error rendering gallery PDF: ', reason);
    });
}

document.addEventListener('DOMContentLoaded', () => {
    setTimeout(() => {
        if (typeof pdfPrimaryBase64 !== 'undefined' && typeof pdfControlBase64 !== 'undefined') {
            renderGalleryPDF(pdfPrimaryBase64, 'pdf-primary-side');
            renderGalleryPDF(pdfControlBase64, 'pdf-control-side');
        }
    }, 200);
});

// pdfBase64 will be appended below by the build script
setTimeout(() => { 
    if (typeof pdfBase64 !== 'undefined') {
        renderPDF(pdfBase64); 
    } else {
        console.error('pdfBase64 not found');
    }
}, 100);

const pdfBase64 = "";

// Lightbox Logic
document.addEventListener('DOMContentLoaded', () => {
    const modal = document.getElementById('lightbox-modal');
    const modalImg = document.getElementById('lightbox-img');
    const closeBtn = document.getElementsByClassName('lightbox-close')[0];

    document.body.addEventListener('click', function(e) {
        if (e.target.tagName === 'IMG' && !e.target.classList.contains('lightbox-content')) {
            modal.style.display = 'flex';
            modalImg.src = e.target.src;
        } else if (e.target.tagName === 'CANVAS') {
            modal.style.display = 'flex';
            modalImg.src = e.target.toDataURL("image/png");
        }
    });

    closeBtn.onclick = function() {
        modal.style.display = 'none';
    }

    modal.addEventListener('click', function(e) {
        if (e.target === modal) {
            modal.style.display = 'none';
        }
    });
});
